#!/usr/bin/env node
/**
 * Knowledge Graph Validation Script
 * Validates schema, referential integrity, completeness, layer coverage,
 * uniqueness, tour validation, quality checks, and type/ID prefix consistency.
 */

const fs = require('fs');

const VALID_NODE_TYPES = [
  'file', 'function', 'class', 'module', 'concept', 'config', 'document',
  'service', 'table', 'endpoint', 'pipeline', 'schema', 'resource',
  'domain', 'flow', 'step'
];

const VALID_NODE_PREFIXES = [
  'file:', 'function:', 'class:', 'module:', 'concept:', 'config:', 'document:',
  'service:', 'table:', 'endpoint:', 'pipeline:', 'schema:', 'resource:',
  'domain:', 'flow:', 'step:'
];

const VALID_EDGE_TYPES = [
  'imports', 'exports', 'contains', 'inherits', 'implements', 'calls',
  'subscribes', 'publishes', 'middleware', 'reads_from', 'writes_to',
  'transforms', 'validates', 'depends_on', 'tested_by', 'configures',
  'related', 'similar_to', 'deploys', 'serves', 'migrates', 'documents',
  'provisions', 'routes', 'defines_schema', 'triggers', 'contains_flow',
  'flow_step', 'cross_domain'
];

const VALID_EDGE_DIRECTIONS = ['forward', 'backward', 'bidirectional'];

const FILE_LEVEL_TYPES = [
  'file', 'config', 'document', 'service', 'pipeline', 'table',
  'schema', 'resource', 'endpoint'
];

function main() {
  const inputPath = process.argv[2];
  const outputPath = process.argv[3];

  if (!inputPath || !outputPath) {
    console.error('Usage: node ua-graph-validate.js <input-graph.json> <output-results.json>') > process.stderr;
    process.exit(1);
  }

  let graph;
  try {
    const content = fs.readFileSync(inputPath, 'utf8');
    graph = JSON.parse(content);
  } catch (err) {
    console.error('Error reading or parsing graph file:', err.message, process.stderr);
    process.exit(1);
  }

  const issues = [];
  const warnings = [];
  const stats = {
    totalNodes: 0,
    totalEdges: 0,
    totalLayers: 0,
    tourSteps: 0,
    nodeTypes: {},
    edgeTypes: {}
  };

  // Build node ID set for quick lookup
  const nodeIds = new Set();
  const nodeIdIndices = {}; // Track indices of nodes with same ID

  // Detect if domain graph
  const isDomainGraph = graph.nodes && graph.nodes.some(n =>
    n.type === 'domain' || n.type === 'flow' || n.type === 'step'
  );

  // --- CHECK 1: Schema Validation ---
  validateSchema(graph, issues, stats, nodeIds, nodeIdIndices);

  // --- CHECK 2: Referential Integrity ---
  validateReferentialIntegrity(graph, issues, nodeIds);

  // --- CHECK 3: Completeness ---
  validateCompleteness(graph, issues, warnings, isDomainGraph);

  // --- CHECK 4: Layer Coverage ---
  const layers = graph.layers || [];
  validateLayerCoverage(graph, issues, warnings, nodeIds, layers, isDomainGraph);

  // --- CHECK 5: Uniqueness ---
  validateUniqueness(nodeIdIndices, issues);

  // --- CHECK 6: Tour Validation ---
  const tour = graph.tour || [];
  validateTour(tour, issues, warnings, stats, nodeIds, isDomainGraph);

  // --- CHECK 7: Quality Checks ---
  validateQuality(graph, warnings);

  // --- CHECK 8: Non-Code Node Quality Checks ---
  validateNonCodeNodes(graph, warnings);

  // --- CHECK 9: Node Type / ID Prefix Consistency ---
  validateTypeIdConsistency(graph, warnings);

  // Calculate stats from graph
  if (graph.nodes) stats.totalNodes = graph.nodes.length;
  if (graph.edges) stats.totalEdges = graph.edges.length;
  stats.totalLayers = layers.length;
  stats.tourSteps = tour.length;

  // Count node types
  if (graph.nodes) {
    graph.nodes.forEach(n => {
      stats.nodeTypes[n.type] = (stats.nodeTypes[n.type] || 0) + 1;
    });
  }

  // Count edge types
  if (graph.edges) {
    graph.edges.forEach(e => {
      stats.edgeTypes[e.type] = (stats.edgeTypes[e.type] || 0) + 1;
    });
  }

  const result = {
    scriptCompleted: true,
    issues,
    warnings,
    stats
  };

  try {
    fs.writeFileSync(outputPath, JSON.stringify(result, null, 2), 'utf8');
  } catch (err) {
    console.error('Error writing output file:', err.message, process.stderr);
    process.exit(1);
  }

  console.log('Validation complete. Results written to:', outputPath);
}

function validateSchema(graph, issues, stats, nodeIds, nodeIdIndices) {
  const nodes = graph.nodes || [];

  nodes.forEach((node, idx) => {
    // Track node IDs for uniqueness check
    if (nodeIdIndices[node.id]) {
      nodeIdIndices[node.id].push(idx);
    } else {
      nodeIdIndices[node.id] = [idx];
    }
    nodeIds.add(node.id);

    // Required fields
    if (!node.id || typeof node.id !== 'string' || node.id.trim() === '') {
      issues.push(`Node at index ${idx} has missing or empty 'id' field`);
    }

    if (!node.type || typeof node.type !== 'string') {
      issues.push(`Node '${node.id || idx}' has missing or invalid 'type' field`);
    } else if (!VALID_NODE_TYPES.includes(node.type)) {
      issues.push(`Node '${node.id}' has invalid type '${node.type}'. Valid types: ${VALID_NODE_TYPES.join(', ')}`);
    }

    if (!node.name || typeof node.name !== 'string' || node.name.trim() === '') {
      issues.push(`Node '${node.id || idx}' has missing or empty 'name' field`);
    }

    if (!node.summary || typeof node.summary !== 'string' || node.summary.trim() === '') {
      issues.push(`Node '${node.id || idx}' has missing or empty 'summary' field`);
    }

    if (!Array.isArray(node.tags) || node.tags.length === 0) {
      issues.push(`Node '${node.id || idx}' has missing or empty 'tags' array`);
    } else {
      const invalidTags = node.tags.filter(t => typeof t !== 'string' || t !== t.toLowerCase() || t.includes('_'));
      if (invalidTags.length > 0) {
        issues.push(`Node '${node.id || idx}' has invalid tags (must be lowercase and hyphenated): ${invalidTags.join(', ')}`);
      }
    }

    if (!node.complexity || typeof node.complexity !== 'string') {
      issues.push(`Node '${node.id || idx}' has missing or invalid 'complexity' field`);
    } else if (!['simple', 'moderate', 'complex'].includes(node.complexity)) {
      issues.push(`Node '${node.id || idx}' has invalid complexity '${node.complexity}'. Valid values: simple, moderate, complex`);
    }
  });

  const edges = graph.edges || [];

  edges.forEach((edge, idx) => {
    if (!edge.source || typeof edge.source !== 'string' || edge.source.trim() === '') {
      issues.push(`Edge at index ${idx} has missing or empty 'source' field`);
    }

    if (!edge.target || typeof edge.target !== 'string' || edge.target.trim() === '') {
      issues.push(`Edge at index ${idx} has missing or empty 'target' field`);
    }

    if (!edge.type || typeof edge.type !== 'string') {
      issues.push(`Edge at index ${idx} (source: '${edge.source || 'unknown'}') has missing or invalid 'type' field`);
    } else if (!VALID_EDGE_TYPES.includes(edge.type)) {
      issues.push(`Edge at index ${idx} has invalid type '${edge.type}'. Valid types: ${VALID_EDGE_TYPES.join(', ')}`);
    }

    if (!edge.direction || typeof edge.direction !== 'string') {
      issues.push(`Edge at index ${idx} (source: '${edge.source || 'unknown'}') has missing or invalid 'direction' field`);
    } else if (!VALID_EDGE_DIRECTIONS.includes(edge.direction)) {
      issues.push(`Edge at index ${idx} has invalid direction '${edge.direction}'. Valid values: ${VALID_EDGE_DIRECTIONS.join(', ')}`);
    }

    if (typeof edge.weight !== 'number' || edge.weight < 0.0 || edge.weight > 1.0) {
      issues.push(`Edge at index ${idx} (source: '${edge.source || 'unknown'}') has invalid weight '${edge.weight}'. Must be between 0.0 and 1.0`);
    }
  });
}

function validateReferentialIntegrity(graph, issues, nodeIds) {
  const edges = graph.edges || [];
  const layers = graph.layers || [];
  const tour = graph.tour || [];

  edges.forEach((edge, idx) => {
    if (edge.source && !nodeIds.has(edge.source)) {
      issues.push(`Edge at index ${idx} references non-existent source node '${edge.source}'`);
    }
    if (edge.target && !nodeIds.has(edge.target)) {
      issues.push(`Edge at index ${idx} references non-existent target node '${edge.target}'`);
    }
  });

  layers.forEach((layer, idx) => {
    if (layer.nodeIds) {
      layer.nodeIds.forEach(nodeId => {
        if (!nodeIds.has(nodeId)) {
          issues.push(`Layer at index ${idx} (id: '${layer.id || 'unknown'}') references non-existent node '${nodeId}'`);
        }
      });
    }
  });

  tour.forEach((step, idx) => {
    if (step.nodeIds) {
      step.nodeIds.forEach(nodeId => {
        if (!nodeIds.has(nodeId)) {
          issues.push(`Tour step at index ${idx} (order: ${step.order || 'unknown'}) references non-existent node '${nodeId}'`);
        }
      });
    }
  });
}

function validateCompleteness(graph, issues, warnings, isDomainGraph) {
  const nodes = graph.nodes || [];
  const edges = graph.edges || [];
  const layers = graph.layers || [];
  const tour = graph.tour || [];

  if (nodes.length === 0) {
    issues.push('Graph has zero nodes - at least 1 node is required');
  }

  if (edges.length === 0) {
    issues.push('Graph has zero edges - at least 1 edge is required');
  }

  if (layers.length === 0) {
    if (isDomainGraph) {
      warnings.push('Domain graph has zero layers - this is acceptable for domain graphs');
    } else {
      issues.push('Graph has zero layers - at least 1 layer is required');
    }
  }

  if (tour.length === 0) {
    if (isDomainGraph) {
      warnings.push('Domain graph has zero tour steps - this is acceptable for domain graphs');
    } else {
      issues.push('Graph has zero tour steps - at least 1 tour step is required');
    }
  }
}

function validateLayerCoverage(graph, issues, warnings, nodeIds, layers, isDomainGraph) {
  const nodes = graph.nodes || [];

  // Count how many layers each node appears in
  const nodeLayerCount = {};
  layers.forEach(layer => {
    if (layer.nodeIds) {
      layer.nodeIds.forEach(nodeId => {
        nodeLayerCount[nodeIdId] = (nodeLayerCount[nodeId] || 0) + 1;
      });
    }
  });

  // Check file-level nodes for layer coverage
  nodes.forEach(node => {
    if (FILE_LEVEL_TYPES.includes(node.type)) {
      const count = nodeLayerCount[node.id] || 0;
      if (count === 0) {
        issues.push(`File-level node '${node.id}' is missing from all layers`);
      } else if (count > 1) {
        issues.push(`File-level node '${node.id}' appears in ${count} layers (should be exactly 1)`);
      }
    }
  });

  // Check for empty layers
  layers.forEach((layer, idx) => {
    if (!layer.nodeIds || layer.nodeIds.length === 0) {
      issues.push(`Layer at index ${idx} (id: '${layer.id || 'unknown'}') has empty nodeIds array`);
    }
  });
}

function validateUniqueness(nodeIdIndices, issues) {
  Object.entries(nodeIdIndices).forEach(([id, indices]) => {
    if (indices.length > 1) {
      issues.push(`Duplicate node ID '${id}' appears at indices: ${indices.join(', ')}`);
    }
  });
}

function validateTour(tour, issues, warnings, stats, nodeIds, isDomainGraph) {
  if (tour.length === 0) return;

  const orderValues = new Set();
  const hasOrderIssue = false;

  tour.forEach((step, idx) => {
    if (step.order !== idx + 1) {
      hasOrderIssue = true;
    }
    if (orderValues.has(step.order)) {
      issues.push(`Tour step at index ${idx} has duplicate order value ${step.order}`);
    }
    orderValues.add(step.order);

    if (!step.nodeIds || step.nodeIds.length === 0) {
      issues.push(`Tour step at index ${idx} (order: ${step.order || 'unknown'}) has empty nodeIds array`);
    }
  });

  if (hasOrderIssue) {
    warnings.push('Tour steps do not have sequential order values starting from 1');
  }

  if (tour.length < 5) {
    warnings.push(`Tour has only ${tour.length} steps - recommended between 5 and 15`);
  } else if (tour.length > 15) {
    warnings.push(`Tour has ${tour.length} steps - recommended between 5 and 15`);
  }
}

function validateQuality(graph, warnings) {
  const nodes = graph.nodes || [];
  const edges = graph.edges || [];
  const nodeIds = new Set(nodes.map(n => n.id));

  // Check for self-referencing edges
  edges.forEach(edge => {
    if (edge.source === edge.target) {
      warnings.push(`Self-referencing edge found: source and target both '${edge.source}'`);
    }
  });

  // Check for orphan nodes
  const connectedNodes = new Set();
  edges.forEach(edge => {
    connectedNodes.add(edge.source);
    connectedNodes.add(edge.target);
  });

  const orphanNodes = nodes.filter(n => !connectedNodes.has(n.id));
  if (orphanNodes.length > 0) {
    warnings.push(`${orphanNodes.length} node(s) have no edges connecting to them: ${orphanNodes.map(n => n.id).join(', ')}`);
  }

  // Check for generic/short summaries
  nodes.forEach(node => {
    if (node.summary) {
      const summary = node.summary.trim();
      const name = node.name || '';

      // Check if summary is just the filename
      const filenameFromPath = node.filePath ? node.filePath.split('/').pop() : '';

      if (summary.length < 20) {
        warnings.push(`Node '${node.id}' has a very short summary (${summary.length} chars)`);
      }

      if (summary === name || summary === filenameFromPath) {
        warnings.push(`Node '${node.id}' has a summary that merely restates the name/filename`);
      }
    }
  });
}

function validateNonCodeNodes(graph, warnings) {
  const nodes = graph.nodes || [];
  const edges = graph.edges || [];

  const nodeEdgeTypes = {};
  edges.forEach(edge => {
    if (!nodeEdgeTypes[edge.source]) nodeEdgeTypes[edge.source] = new Set();
    nodeEdgeTypes[edge.source].add(edge.type);
  });

  nodes.forEach(node => {
    const outgoingTypes = nodeEdgeTypes[node.id] || new Set();

    switch (node.type) {
      case 'document':
        if (!outgoingTypes.has('documents')) {
          warnings.push(`Document node '${node.id}' has no 'documents' edges`);
        }
        break;
      case 'service':
        if (!outgoingTypes.has('deploys') && !outgoingTypes.has('depends_on')) {
          warnings.push(`Service node '${node.id}' has no 'deploys' or 'depends_on' edges`);
        }
        break;
      case 'pipeline':
        if (!outgoingTypes.has('triggers')) {
          warnings.push(`Pipeline node '${node.id}' has no 'triggers' edges`);
        }
        break;
      case 'table':
        if (!outgoingTypes.has('migrates') && !outgoingTypes.has('defines_schema')) {
          warnings.push(`Table node '${node.id}' has no 'migrates' or 'defines_schema' edges`);
        }
        break;
      case 'schema':
        if (!outgoingTypes.has('defines_schema')) {
          warnings.push(`Schema node '${node.id}' has no 'defines_schema' edges`);
        }
        break;
      case 'domain':
        if (!outgoingTypes.has('contains_flow')) {
          warnings.push(`Domain node '${node.id}' has no 'contains_flow' edges`);
        }
        break;
      case 'flow':
        if (!outgoingTypes.has('flow_step')) {
          warnings.push(`Flow node '${node.id}' has no 'flow_step' edges`);
        }
        break;
    }
  });
}

function validateTypeIdConsistency(graph, warnings) {
  const nodes = graph.nodes || [];

  nodes.forEach(node => {
    if (!node.id || !node.type) return;

    const expectedPrefix = node.type + ':';
    if (!node.id.startsWith(expectedPrefix)) {
      warnings.push(`Node '${node.id}' has type '${node.type}' but ID does not start with '${expectedPrefix}'`);
    }
  });
}

main();
